const fs = require('fs');
const path = require('path');

const { NORDIC_BUILD_DIR } = require('./constants');

/** @type {Record<string, string>} */
const TS_TO_JS_EXT = { '.ts': '', '.tsx': '', '.mts': '.mjs', '.cts': '.cjs' };

const CJS_CONDITIONS = ['require', 'node', 'module-sync', 'default'];
const ESM_CONDITIONS = ['import', 'node', 'module-sync', 'default'];

// eslint-disable-next-line import/no-dynamic-require
const pkg = require(path.resolve('package.json'));

/**
 * @param {string | Record<string, string> | null} value
 * @param {string[]} conditions
 * @returns {string | null}
 */
function resolveImportCondition(value, conditions) {
  if (typeof value === 'string') {
    return value;
  }

  if (typeof value !== 'object' || value === null) {
    return null;
  }

  const match = conditions.find((condition) => condition in value);

  return match ? resolveImportCondition(value[match], conditions) : null;
}

/**
 * @param {Object} [options]
 * @param {boolean} [options.isBabelClient]
 * @param {string} [options.filename]
 * @returns {Record<string, string> | null}
 */
function resolveSubpathImports({ isBabelClient = false, filename } = {}) {
  if (!pkg.imports) {
    return null;
  }

  const fileExt = filename ? path.extname(filename) : null;

  const isEsm =
    fileExt === '.mts' ||
    fileExt === '.mjs' ||
    (fileExt !== '.cts' && fileExt !== '.cjs' && pkg.type === 'module');

  const conditions = isEsm ? ESM_CONDITIONS : CJS_CONDITIONS;

  const outDir =
    !isBabelClient &&
    !process.argv.includes('ts-node/register') &&
    // eslint-disable-next-line security/detect-non-literal-fs-filename
    fs.existsSync(path.resolve(NORDIC_BUILD_DIR))
      ? NORDIC_BUILD_DIR
      : null;

  /** @type {Record<string, string>} */
  const aliases = {};

  Object.entries(pkg.imports).forEach(([key, importValue]) => {
    const value = resolveImportCondition(importValue, conditions);

    if (!value?.startsWith('./')) {
      return;
    }

    const alias = key.replace('/*', '');
    const wildcardIndex = value.indexOf('/*');
    const ext = path.extname(value);

    let resolvedPath = value;

    if (wildcardIndex !== -1) {
      resolvedPath = value.slice(0, wildcardIndex);
    } else if (outDir && ext in TS_TO_JS_EXT) {
      resolvedPath = value.slice(0, -ext.length) + TS_TO_JS_EXT[ext];
    }

    aliases[alias] = outDir
      ? path.resolve(outDir, resolvedPath)
      : path.resolve(resolvedPath);
  });

  return Object.keys(aliases).length ? aliases : null;
}

module.exports = resolveSubpathImports;
